 38→	ctxSection,
 39→	type PromptMemoryData,
 40→	promptMemoryDetailParts,
 41→	renderContextMcpSection,
 42→	renderContextProjectSection,
 43→	renderContextPromptMemorySection,
 44→	renderContextSandboxSection,
 45→	renderContextSessionSection,
 46→	renderContextSkillsSection,
 47→	renderContextTokensSection,
 48→	renderContextToolsSection,
 49→} from "./chat/context-card";
 50→// ── Sub-module imports ──────────────────────────────────────
 51→import {
 52→	setSendChatFn,
 53→	slashHandleInput,
 54→	slashHandleKeydown,
 55→	slashHideMenu,
 56→	slashInjectStyles,
