 58→
 59→// ── Module state ─────────────────────────────────────────────
 60→let chatMoreModalKeydownHandler: ((e: KeyboardEvent) => void) | null = null;
 61→let disposeSessionControlsVisibility: (() => void) | null = null;
 62→let promptMemoryToolbarRequestId = 0;
 63→
 64→// ── Prompt memory toolbar helpers ─────────────────────────────
 65→
 66→function promptMemoryToolbarTitle(promptMemory: PromptMemoryData | null): string {
 67→	if (!promptMemory) return "Prompt memory unavailable";
 68→	const parts = [`Prompt memory: ${buildPromptMemorySummary(promptMemory)}`];
 69→	const dp = promptMemoryDetailParts(promptMemory);
 70→	if (dp.length > 0) parts.push(dp.join(" \u00b7 "));
 71→	return parts.join("\n");
 72→}
 73→
 74→function promptMemoryToolbarLabel(promptMemory: PromptMemoryData | null): string {
 75→	if (!promptMemory) return "Memory";
 76→	if (promptMemory.mode === "frozen-at-session-start") return "Memory frozen";
 77→	if (promptMemory.mode === "live-reload") return "Memory live";
 78→	return "Memory";
 79→}
 80→
 81→function setPromptMemoryToolbarState(pm: PromptMemoryData | null, loading: boolean, refreshing: boolean): void {
 82→	const toolbar = S.$("promptMemoryToolbar") as HTMLElement | null;
 83→	const statusBtn = S.$("promptMemoryStatusBtn") as HTMLButtonElement | null;
 84→	const statusLabel = S.$("promptMemoryStatusLabel") as HTMLElement | null;
 85→	const refreshBtn = S.$("promptMemoryRefreshBtn") as HTMLButtonElement | null;
 86→	if (!(toolbar && statusBtn && statusLabel && refreshBtn)) return;
 87→	toolbar.classList.remove("hidden");
 88→	toolbar.classList.add("inline-flex");
 89→	statusBtn.disabled = !!loading;
 90→	refreshBtn.disabled = !!refreshing;
 91→	if (loading) {
 92→		statusLabel.textContent = "Memory\u2026";
 93→		statusBtn.title = "Loading prompt memory status";
 94→		refreshBtn.classList.add("hidden");
 95→		return;
 96→	}
 97→	statusLabel.textContent = promptMemoryToolbarLabel(pm);
 98→	statusBtn.title = promptMemoryToolbarTitle(pm);
 99→	refreshBtn.classList.toggle("hidden", pm?.mode !== "frozen-at-session-start");
100→	refreshBtn.title = pm?.mode === "frozen-at-session-start" ? "Refresh frozen prompt memory" : "Refresh unavailable";
101→}
102→
103→function refreshPromptMemoryToolbarFromPayload(pm: PromptMemoryData | null): void {
104→	setPromptMemoryToolbarState(pm || null, false, false);
105→}
106→
107→function refreshPromptMemoryToolbar(): Promise<PromptMemoryData | null> {
108→	if (!S.connected) {
109→		setPromptMemoryToolbarState(null, false, false);
110→		return Promise.resolve(null);
111→	}
112→	const requestId = ++promptMemoryToolbarRequestId;
113→	setPromptMemoryToolbarState(null, true, false);
114→	return sendRpc("chat.context", {}).then((res: any) => {
115→		if (requestId !== promptMemoryToolbarRequestId) return null;
116→		if (res?.ok && res.payload) {
117→			const pm = res.payload.promptMemory || null;
118→			refreshPromptMemoryToolbarFromPayload(pm);
119→			return pm;
120→		}
121→		setPromptMemoryToolbarState(null, false, false);
122→		return null;
123→	});
124→}
125→
126→function refreshPromptMemoryToolbarSnapshot(): Promise<PromptMemoryData | null> {
127→	setPromptMemoryToolbarState(null, false, true);
128→	return sendRpc("chat.prompt_memory.refresh", {})
129→		.then((res: any) => {
130→			if (!(res?.ok && res.payload)) throw new Error(res?.error?.message || "Failed to refresh prompt memory");
131→			const pm = res.payload.promptMemory || null;
132→			refreshPromptMemoryToolbarFromPayload(pm);
133→			maybeRefreshFullContext();
134→			return pm;
135→		})
136→		.catch((error: any) => {
137→			refreshPromptMemoryToolbar();
138→			chatAddMsg("error", error?.message || "Failed to refresh prompt memory");
139→			return null;
140→		});
141→}
142→
143→// ── Compact card ─────────────────────────────────────────────
144→
145→interface CompactCardData {
146→	mode?: string;
147→	messageCount?: number;
148→	totalTokens?: number;
149→	estimatedNextInputTokens?: number;
150→	contextWindow?: number;
151→	compactionTotalTokens?: number;
152→	compactionInputTokens?: number;
153→	compactionOutputTokens?: number;
154→	settingsHint?: string;
155→}
156→
157→const COMPACTION_MODE_LABELS: Record<string, string> = {
158→	deterministic: "Deterministic",
159→	recency_preserving: "Recency preserving",
160→	structured: "Structured",
161→	llm_replace: "LLM replace",
162→};
163→
164→function compactionModeLabel(mode: string | undefined): string {
165→	if (!mode) return "Unknown";
166→	return COMPACTION_MODE_LABELS[mode] || mode;
167→}
168→
169→export function renderCompactCard(data: CompactCardData): void {
170→	if (!S.chatMsgBox) return;
171→	slashInjectStyles();
172→	const card = ctxEl("div", "ctx-card");
173→	const header = ctxEl("div", "ctx-header");
174→	const icon = document.createElement("span");
175→	icon.className = "icon icon-compress";
176→	header.appendChild(icon);
177→	header.appendChild(ctxEl("span", "ctx-header-title", "Conversation compacted"));
178→	card.appendChild(header);
179→	if (data.mode) {
180→		const stratSec = ctxSection("Strategy");
181→		stratSec.appendChild(ctxRow("Mode", compactionModeLabel(data.mode)));
182→		const totalTokens = Number(data.compactionTotalTokens || 0);
183→		if (totalTokens > 0) {
184→			const inp = Number(data.compactionInputTokens || 0);
185→			const outp = Number(data.compactionOutputTokens || 0);
186→			stratSec.appendChild(
187→				ctxRow("Tokens used", `${formatTokens(totalTokens)} (${formatTokens(inp)} in + ${formatTokens(outp)} out)`),
188→			);
189→		} else {
190→			stratSec.appendChild(ctxRow("Tokens used", "0 (no LLM call)"));
191→		}
192→		card.appendChild(stratSec);
193→	}
194→	const statsSec = ctxSection("Before compact");
195→	statsSec.appendChild(ctxRow("Messages", String(data.messageCount || 0)));
196→	if (data.totalTokens) statsSec.appendChild(ctxRow("Total tokens", formatTokens(data.totalTokens || 0)));
197→	if (data.estimatedNextInputTokens)
198→		statsSec.appendChild(ctxRow("Estimated next input", formatTokens(data.estimatedNextInputTokens), true));
199→	if (data.contextWindow) {
200→		const basis = data.estimatedNextInputTokens || data.totalTokens || 0;
201→		const pctUsed = Math.round((basis / data.contextWindow) * 100);
202→		statsSec.appendChild(ctxRow("Context usage", `${pctUsed}% of ${formatTokens(data.contextWindow)}`));
203→	}
204→	card.appendChild(statsSec);
205→	const afterSec = ctxSection("After compact");
206→	const replacesAll = data.mode === "deterministic" || data.mode === "llm_replace" || !data.mode;
207→	if (replacesAll) {
208→		afterSec.appendChild(ctxRow("Messages", "1 (summary)"));
209→		afterSec.appendChild(ctxRow("Status", "Conversation history replaced with a summary"));
210→	} else {
211→		afterSec.appendChild(ctxRow("Status", "Head + tail preserved verbatim; middle summarised"));
212→	}
213→	card.appendChild(afterSec);
214→	if (data.settingsHint) {
215→		const hintSec = ctxSection("Configure");
216→		const hintRow = ctxEl("div", "ctx-value");
217→		hintRow.textContent = data.settingsHint;
218→		hintSec.appendChild(hintRow);
219→		card.appendChild(hintSec);
220→	}
221→	S.chatMsgBox.appendChild(card);
222→	S.chatMsgBox.scrollTop = S.chatMsgBox.scrollHeight;
223→}
