225→// ── Debug / full context panels ──────────────────────────────
226→
227→interface ContextMessage {
228→	role?: string;
229→	content?: unknown;
230→	tool_calls?: Array<{
231→		id?: string;
232→		function?: { name?: string; arguments?: string };
233→	}>;
234→	tool_call_id?: string;
235→}
236→
237→function setDebugModalOpen(open: boolean): void {
238→	const modal = S.$("debugModal") as HTMLElement | null;
239→	if (!modal) return;
240→	modal.classList.toggle("hidden", !open);
241→	const btn = S.$("debugPanelBtn") as HTMLElement | null;
242→	if (btn) btn.style.color = open ? "var(--accent)" : "var(--muted)";
243→}
244→
245→function setFullContextModalOpen(open: boolean): void {
246→	const modal = S.$("fullContextModal") as HTMLElement | null;
247→	if (!modal) return;
248→	modal.classList.toggle("hidden", !open);
249→	const btn = S.$("fullContextBtn") as HTMLElement | null;
250→	if (btn) btn.style.color = open ? "var(--accent)" : "var(--muted)";
251→}
252→
253→function refreshDebugPanel(): void {
254→	const panel = S.$("debugPanel") as HTMLElement | null;
255→	if (!panel) return;
256→	panel.textContent = "";
257→	panel.appendChild(ctxEl("div", "text-xs text-[var(--muted)]", "Loading context\u2026"));
258→	sendRpc("chat.context", {}).then((res: any) => {
259→		panel.textContent = "";
260→		if (!(res?.ok && res.payload)) {
261→			panel.appendChild(ctxEl("div", "text-xs text-[var(--error)]", "Failed to load context"));
262→			return;
263→		}
264→		slashInjectStyles();
265→		renderContextSessionSection(panel, res.payload);
266→		renderContextProjectSection(panel, res.payload);
267→		renderContextSkillsSection(panel, res.payload);
268→		renderContextMcpSection(panel, res.payload);
269→		renderContextToolsSection(panel, res.payload);
270→		renderContextSandboxSection(panel, res.payload);
271→		renderContextPromptMemorySection(panel, res.payload);
272→		renderContextTokensSection(panel, res.payload);
273→		refreshPromptMemoryToolbarFromPayload(res.payload.promptMemory || null);
274→	});
275→}
276→
277→function toggleDebugPanel(): void {
278→	const modal = S.$("debugModal") as HTMLElement | null;
279→	if (!modal) return;
280→	const opening = modal.classList.contains("hidden");
281→	if (!opening) {
282→		setDebugModalOpen(false);
283→		return;
284→	}
285→	setFullContextModalOpen(false);
286→	setDebugModalOpen(true);
287→	refreshDebugPanel();
288→}
289→
290→// ── Full context panel ───────────────────────────────────────
291→const ROLE_COLORS: Record<string, string> = {
292→	system: "var(--accent)",
293→	user: "var(--ok, #22c55e)",
294→	assistant: "var(--info, #3b82f6)",
295→	tool: "var(--muted)",
296→};
297→
298→function ctxMsgBadge(role: string): HTMLElement {
299→	const color = ROLE_COLORS[role] || "var(--text)";
300→	const badge = ctxEl("span", "text-xs font-semibold uppercase px-1.5 py-0.5 rounded");
301→	badge.style.cssText = `color:${color};background:color-mix(in srgb, ${color} 15%, transparent)`;
302→	badge.textContent = role;
303→	return badge;
304→}
305→
306→function ctxMsgMeta(msg: ContextMessage, contentStr: string): string {
307→	const parts: string[] = [];
308→	const chars = contentStr ? contentStr.length : 0;
309→	if (chars > 0) parts.push(`${chars.toLocaleString()} chars`);
310→	const toolCalls = msg.tool_calls || [];
311→	if (toolCalls.length > 0) parts.push(`${toolCalls.length} tool call${toolCalls.length > 1 ? "s" : ""}`);
312→	if (msg.role === "tool" && msg.tool_call_id) parts.push(`id: ${msg.tool_call_id}`);
313→	return parts.join(" \u00b7 ");
314→}
315→
316→function ctxMsgToolCall(tc: NonNullable<ContextMessage["tool_calls"]>[number]): HTMLElement {
317→	const div = ctxEl("div", "mt-1 border border-[var(--border)] rounded-md p-2 bg-[var(--surface)]");
318→	const hdr = ctxEl("div", "text-xs font-semibold text-[var(--text)] mb-1");
319→	hdr.textContent = `\ud83d\udee0 ${tc.function?.name || "unknown"}`;
320→	if (tc.id) hdr.appendChild(ctxEl("span", "font-normal text-[var(--muted)] ml-2", `id: ${tc.id}`));
321→	div.appendChild(hdr);
322→	if (tc.function?.arguments) {
323→		const pre = ctxEl("pre", "text-xs font-mono whitespace-pre-wrap break-words text-[var(--text)]");
324→		try {
325→			pre.textContent = JSON.stringify(JSON.parse(tc.function.arguments), null, 2);
326→		} catch {
327→			pre.textContent = tc.function.arguments;
328→		}
329→		div.appendChild(pre);
330→	}
331→	return div;
332→}
333→
334→function renderContextMessage(msg: ContextMessage, index: number): HTMLElement {
335→	const wrapper = ctxEl("div", "mb-2");
336→	const contentStr = typeof msg.content === "string" ? msg.content : JSON.stringify(msg.content, null, 2);
337→	const hdr = ctxEl("div", "flex items-center gap-2 cursor-pointer select-none");
338→	hdr.appendChild(ctxMsgBadge(msg.role || "unknown"));
339→	hdr.appendChild(ctxEl("span", "text-xs text-[var(--muted)]", `#${index}`));
340→	const meta = ctxMsgMeta(msg, contentStr);
341→	if (meta) hdr.appendChild(ctxEl("span", "text-xs text-[var(--muted)]", meta));
342→	const chevron = ctxEl("span", "text-xs text-[var(--muted)] ml-auto");
343→	const startOpen = index !== 0;
344→	chevron.textContent = startOpen ? "\u25bc" : "\u25b6";
345→	hdr.appendChild(chevron);
346→	wrapper.appendChild(hdr);
347→	const body = ctxEl("div", "mt-1");
348→	body.style.display = startOpen ? "block" : "none";
349→	hdr.addEventListener("click", () => {
350→		const open = body.style.display !== "none";
351→		body.style.display = open ? "none" : "block";
352→		chevron.textContent = open ? "\u25b6" : "\u25bc";
353→	});
354→	if (contentStr) {
355→		const pre = ctxEl(
356→			"pre",
357→			"text-xs font-mono whitespace-pre-wrap break-words bg-[var(--surface)] border border-[var(--border)] rounded-md p-2 text-[var(--text)]",
358→		);
359→		pre.textContent = contentStr;
360→		body.appendChild(pre);
361→	}
362→	for (const tc of msg.tool_calls || []) body.appendChild(ctxMsgToolCall(tc));
363→	wrapper.appendChild(body);
364→	return wrapper;
365→}
366→
367→function buildFullContextPromptMemoryBox(pm: PromptMemoryData | null): HTMLElement | null {
368→	if (!pm) return null;
369→	const box = ctxEl(
370→		"div",
371→		"text-xs mb-3 rounded-md border border-[var(--border)] bg-[var(--surface)] p-2 text-[var(--text)]",
372→	);
373→	const summaryLine = ctxEl("div", "font-semibold");
374→	summaryLine.textContent = `Prompt memory: ${buildPromptMemorySummary(pm)}`;
375→	box.appendChild(summaryLine);
376→	const dp = promptMemoryDetailParts(pm);
377→	if (dp.length > 0) box.appendChild(ctxEl("div", "mt-1 text-[var(--muted)]", dp.join(" \u00b7 ")));
378→	return box;
379→}
380→
381→function appendFullContextWorkspaceWarnings(panel: HTMLElement, payload: any): void {
382→	const wf: any[] = Array.isArray(payload.workspaceFiles) ? payload.workspaceFiles : [];
383→	if (!payload.truncated || wf.length === 0) return;
384→	const tf = wf.filter((f: any) => f?.truncated);
385→	if (tf.length === 0) return;
386→	const warning = ctxEl(
387→		"div",
388→		"text-xs mb-3 rounded-md border border-[var(--border)] bg-[var(--surface)] p-2 text-[var(--text)]",
389→	);
390→	warning.textContent = tf
391→		.map((f: any) => {
392→			const name = typeof f.name === "string" ? f.name : "workspace file";
393→			return `${name}: ${Number(f.original_chars || 0).toLocaleString()} chars, limit ${Number(f.limit_chars || 0).toLocaleString()}, truncated by ${Number(f.truncated_chars || 0).toLocaleString()}`;
394→		})
395→		.join(" | ");
396→	panel.appendChild(warning);
397→}
398→
399→function buildFullContextHeaderRow(
400→	payload: any,
401→	onRefresh: (btn: HTMLButtonElement) => void,
402→): { headerRow: HTMLElement; copyBtn: HTMLElement; downloadBtn: HTMLElement; llmOutputBtn: HTMLElement } {
403→	const headerRow = ctxEl("div", "flex items-center gap-3 mb-3");
404→	const headerText = ctxEl("span", "text-xs text-[var(--muted)]");
405→	headerText.textContent = `${payload.messageCount} messages \u00b7 system prompt ${payload.systemPromptChars.toLocaleString()} chars \u00b7 total ${payload.totalChars.toLocaleString()} chars`;
406→	headerRow.appendChild(headerText);
407→	const copyBtn = ctxEl("button", "provider-btn provider-btn-secondary provider-btn-sm");
408→	copyBtn.textContent = "Copy";
409→	const downloadBtn = ctxEl("button", "provider-btn provider-btn-secondary provider-btn-sm");
410→	downloadBtn.textContent = "Download";
411→	const llmOutputBtn = ctxEl("button", "provider-btn provider-btn-secondary provider-btn-sm");
412→	llmOutputBtn.textContent = "LLM output";
413→	headerRow.appendChild(copyBtn);
414→	headerRow.appendChild(downloadBtn);
415→	headerRow.appendChild(llmOutputBtn);
416→	const pm = payload.promptMemory || null;
417→	if (pm?.mode === "frozen-at-session-start") {
418→		const rb = ctxEl("button", "provider-btn provider-btn-secondary provider-btn-sm") as HTMLButtonElement;
419→		rb.textContent = "Refresh memory";
420→		rb.addEventListener("click", () => onRefresh(rb));
421→		headerRow.appendChild(rb);
422→	}
423→	return { headerRow, copyBtn, downloadBtn, llmOutputBtn };
424→}
425→
426→function wireFullContextCopyButton(
427→	copyBtn: HTMLElement,
428→	messages: ContextMessage[],
429→	llmOutputs: any[],
430→	llmOutputPanel: HTMLElement,
431→): void {
432→	copyBtn.addEventListener("click", () => {
433→		const lines = messages.map((m) => {
434→			const content = typeof m.content === "string" ? m.content : JSON.stringify(m.content);
435→			const parts = [content];
436→			for (const tc of m.tool_calls || [])
437→				parts.push(`[tool_call: ${tc.function?.name || "?"} ${tc.function?.arguments || ""}]`);
438→			return `[${m.role}] ${parts.join("\n")}`;
439→		});
440→		const contextText = lines.join("\n");
441→		let copyText = contextText;
442→		const llmOutputVisible = llmOutputPanel && !llmOutputPanel.classList.contains("hidden");
443→		if (llmOutputVisible) copyText = `LLM output:\n${JSON.stringify(llmOutputs, null, 2)}\n\nContext:\n${contextText}`;
444→		navigator.clipboard.writeText(copyText).then(() => {
445→			copyBtn.textContent = "Copied!";
446→			setTimeout(() => {
447→				copyBtn.textContent = "Copy";
448→			}, 1500);
449→		});
450→	});
451→}
452→
453→function wireFullContextDownloadButton(downloadBtn: HTMLElement, messages: ContextMessage[]): void {
454→	downloadBtn.addEventListener("click", () => {
455→		const lines = messages.map((m) => JSON.stringify(m));
456→		const blob = new Blob([`${lines.join("\n")}\n`], { type: "application/x-jsonlines" });
457→		const url = URL.createObjectURL(blob);
458→		const a = document.createElement("a");
459→		a.href = url;
460→		a.download = `context-${new Date().toISOString().slice(0, 19).replace(/[T:]/g, "-")}.jsonl`;
461→		a.click();
462→		URL.revokeObjectURL(url);
463→	});
464→}
465→
466→function buildFullContextLlmOutputPanel(llmOutputs: any[]): HTMLElement {
467→	const panel = ctxEl("div", "hidden mb-3");
468→	panel.appendChild(
469→		ctxEl(
470→			"div",
471→			"text-xs text-[var(--muted)] mb-1",
472→			`${llmOutputs.length} assistant output${llmOutputs.length === 1 ? "" : "s"}`,
473→		),
474→	);
475→	const pre = ctxEl(
476→		"pre",
477→		"text-xs font-mono whitespace-pre-wrap break-words bg-[var(--surface)] border border-[var(--border)] rounded-md p-2 text-[var(--text)]",
478→	);
479→	pre.id = "fullContextLlmOutput";
480→	pre.textContent = JSON.stringify(llmOutputs, null, 2);
481→	panel.appendChild(pre);
482→	return panel;
483→}
484→
485→function wireFullContextLlmOutputToggle(button: HTMLElement, panel: HTMLElement): void {
486→	button.addEventListener("click", () => {
487→		const hidden = panel.classList.contains("hidden");
488→		panel.classList.toggle("hidden", !hidden);
489→		button.textContent = hidden ? "Hide LLM output" : "LLM output";
490→	});
491→}
492→
493→function refreshFullContextMemory(refreshBtn: HTMLButtonElement): void {
494→	refreshBtn.disabled = true;
495→	refreshBtn.textContent = "Refreshing\u2026";
496→	refreshPromptMemoryToolbarSnapshot().then(() => {
497→		refreshBtn.disabled = false;
498→		refreshBtn.textContent = "Refresh memory";
499→	});
500→}
501→
502→function refreshFullContextPanel(): void {
503→	const panel = S.$("fullContextPanel") as HTMLElement | null;
504→	if (!panel) return;
505→	panel.textContent = "";
506→	panel.appendChild(ctxEl("div", "text-xs text-[var(--muted)]", "Building full context\u2026"));
507→	sendRpc("chat.full_context", {}).then((res: any) => {
508→		panel.textContent = "";
509→		if (!(res?.ok && res.payload)) {
510→			panel.appendChild(ctxEl("div", "text-xs text-[var(--error)]", "Failed to build context"));
