606→function handleChatCopy(e: ClipboardEvent): void {
607→	const sel = window.getSelection();
608→	if (!sel || sel.isCollapsed || !S.chatMsgBox) return;
609→	const lines: string[] = [];
610→	for (const msg of S.chatMsgBox.querySelectorAll(".msg")) {
611→		if (!sel.containsNode(msg, true)) continue;
612→		const role = msgRole(msg);
613→		if (!role) continue;
614→		const text = sel.containsNode(msg, false) ? (msg.textContent || "").trim() : sel.toString().trim();
615→		if (text) lines.push(`${role}:\n${text}`);
616→	}
617→	if (lines.length > 1) {
618→		e.preventDefault();
619→		e.clipboardData?.setData("text/plain", lines.join("\n\n"));
620→	}
621→}
