268→export function highlightAndScroll(msgEls: (HTMLElement | null)[], messageIndex: number, query: string): void {
269→	let target: HTMLElement | null = null;
270→	if (messageIndex >= 0 && messageIndex < msgEls.length && msgEls[messageIndex]) {
271→		target = msgEls[messageIndex];
272→	}
273→	const lowerQ = query.toLowerCase();
274→	if (!target || (target.textContent || "").toLowerCase().indexOf(lowerQ) === -1) {
275→		for (const candidate of msgEls) {
276→			if (candidate && (candidate.textContent || "").toLowerCase().indexOf(lowerQ) !== -1) {
277→				target = candidate;
278→				break;
279→			}
280→		}
281→	}
282→	if (!target) return;
283→	msgEls.forEach((el) => {
284→		if (el) highlightTermInElement(el, query);
285→	});
286→	target.scrollIntoView({ behavior: "smooth", block: "center" });
287→	target.classList.add("search-highlight-msg");
288→	setTimeout(() => {
289→		if (!S.chatMsgBox) return;
290→		S.chatMsgBox.querySelectorAll("mark.search-term-highlight").forEach((m) => {
291→			const parent = m.parentNode!;
292→			parent.replaceChild(document.createTextNode(m.textContent || ""), m);
293→			parent.normalize();
294→		});
295→		S.chatMsgBox.querySelectorAll(".search-highlight-msg").forEach((el) => {
296→			el.classList.remove("search-highlight-msg");
297→		});
298→	}, 5000);
299→}
300→
301→export function highlightTermInElement(el: HTMLElement, query: string): void {
302→	const walker = document.createTreeWalker(el, NodeFilter.SHOW_TEXT, null);
303→	const nodes: Text[] = [];
304→	while (walker.nextNode()) nodes.push(walker.currentNode as Text);
305→	const lowerQ = query.toLowerCase();
306→	nodes.forEach((textNode) => {
307→		const text = textNode.nodeValue || "";
308→		const lowerText = text.toLowerCase();
309→		let idx = lowerText.indexOf(lowerQ);
310→		if (idx === -1) return;
311→		const frag = document.createDocumentFragment();
312→		let pos = 0;
313→		while (idx !== -1) {
314→			if (idx > pos) frag.appendChild(document.createTextNode(text.substring(pos, idx)));
315→			const mark = document.createElement("mark");
316→			mark.className = "search-term-highlight";
317→			mark.textContent = text.substring(idx, idx + query.length);
318→			frag.appendChild(mark);
319→			pos = idx + query.length;
320→			idx = lowerText.indexOf(lowerQ, pos);
321→		}
322→		if (pos < text.length) frag.appendChild(document.createTextNode(text.substring(pos)));
323→		textNode.parentNode?.replaceChild(frag, textNode);
324→	});
325→}
