121→export function buildChatMessage(
122→	text: string,
123→	seq: number,
124→	displayText?: string,
125→): { params: ChatSendParams; el: HTMLElement | null } {
126→	const userText = displayText !== undefined ? displayText : text;
127→	const images = hasPendingImages() ? getPendingImages() : [];
128→	if (images.length > 0) {
129→		const content: ChatContentPart[] = [];
130→		if (text) content.push({ type: "text", text });
131→		for (const img of images)
132→			content.push({ type: "image_url", image_url: { url: (img as { dataUrl: string }).dataUrl } });
133→		const params: ChatSendParams = { content, _seq: seq };
