177→export function sendChat(): void {
178→	const text = (S.chatInput as HTMLTextAreaElement).value.trim();
179→	const hasImages = hasPendingImages();
180→	if (!((text || hasImages) && S.connected)) return;
181→	warmAudioPlayback();
182→	if (tryHandleLocalSlashCommand(text, hasImages)) return;
183→	rememberChatHistory(text);
184→	resetComposerAfterSend();
185→	const outgoingText = normalizeOutgoingText(text, hasImages);
186→	S.setChatSeq(S.chatSeq + 1);
187→	const msg = buildChatMessage(outgoingText, S.chatSeq, text);
188→	const chatParams = msg.params;
189→	const userEl = msg.el;
190→	if (userEl) highlightCodeBlocks(userEl);
191→	applySelectedModelToChatParams(chatParams);
192→	bumpSessionCount(S.activeSessionKey, 1);
193→	cacheOutgoingUserMessage(S.activeSessionKey, chatParams);
194→	seedSessionPreviewFromUserText(S.activeSessionKey, text || outgoingText);
195→	setSessionReplying(S.activeSessionKey, true);
196→	sendRpc<ChatSendPayload>("chat.send", chatParams).then((res) => handleChatSendRpcResponse(res, userEl));
197→	maybeRefreshFullContextFn?.();
198→}
