183→// Handle user messages broadcast by the backend after persisting a message
184→// sent via the GraphQL API, mobile app, or any non-web-UI client.
185→// The originating web client already rendered the message optimistically,
186→// so we skip rendering when the broadcast's seq matches a seq this client
187→// has already sent (seq <= S.chatSeq).
188→function handleChatUserMessage(p: ChatPayload, isActive: boolean, isChatPage: boolean, eventSession: string): void {
189→	// Suppress the echo for the originating client.
190→	if (p.seq !== undefined && p.seq !== null && p.seq <= S.chatSeq) return;
191→
192→	bumpSessionCount(eventSession, 1);
193→	cacheSessionHistoryMessage(
194→		eventSession,
195→		{
196→			role: "user",
197→			content: p.text || "",
198→			created_at: Date.now(),
199→		},
200→		p.messageIndex,
201→	);
202→	if (!isActive) {
203→		setSessionUnread(eventSession, true);
204→	}
205→	if (!(isChatPage && isActive)) return;
206→	// Safe: renderMarkdown calls esc() first -- all user input is
207→	// HTML-escaped before formatting tags are applied.
208→	chatAddMsg("user", renderMarkdown(p.text || ""), true);
209→}
