211→function handleChatDelta(p: ChatPayload, isActive: boolean, isChatPage: boolean, eventSession: string): void {
212→	updateSessionRunId(eventSession, p.runId);
213→	if (!p.text) return;
214→	// Update per-session signal
215→	const session = sessionStore.getByKey(eventSession);
216→	if (session) session.streamText.value += p.text;
217→	if (!(isActive && isChatPage)) return;
218→	// When voice is pending, accumulate text silently without rendering.
219→	if (S.voicePending) {
220→		S.setStreamText(S.streamText + p.text);
221→		return;
222→	}
223→	// Skip leading whitespace before any real content has been streamed.
224→	// Some providers emit newlines between thinking and content; rendering
225→	// them would create an empty assistant div that lingers if a tool call
226→	// follows immediately.  We must check this BEFORE removeThinking() so
227→	// the thinking text is still available for handleChatToolCallStart to
228→	// extract into a reasoning disclosure on the tool card.
229→	if (!(S.streamEl || p.text.trim())) return;
230→	removeThinking();
231→	if (!S.streamEl) {
232→		S.setStreamText("");
233→		S.setStreamEl(document.createElement("div"));
234→		S.streamEl!.className = "msg assistant";
235→		clearChatEmptyState();
236→		S.chatMsgBox?.appendChild(S.streamEl!);
237→	}
238→	S.setStreamText(S.streamText + p.text);
239→	setSafeMarkdownHtml(S.streamEl!, S.streamText);
240→	if (S.chatMsgBox) S.chatMsgBox.scrollTop = S.chatMsgBox.scrollHeight;
241→}
