243→// biome-ignore lint/complexity/noExcessiveCognitiveComplexity: Final message handling with audio/voice branching
244→function handleChatFinal(p: ChatPayload, isActive: boolean, isChatPage: boolean, eventSession: string): void {
245→	clearPendingToolCallEndsForSession(eventSession);
246→	updateSessionRunId(eventSession, p.runId);
247→	// Always bump badge -- the server persists the final assistant message.
248→	bumpSessionCount(eventSession, 1);
249→	const finalText = String(p.text || "");
250→	const hasVisibleFinal =
251→		hasNonWhitespaceContent(finalText) ||
252→		hasNonWhitespaceContent(p.reasoning || "") ||
253→		hasNonWhitespaceContent(p.audio || "");
254→	if (hasVisibleFinal) {
255→		cacheSessionHistoryMessage(
256→			eventSession,
257→			{
258→				role: "assistant",
259→				content: finalText,
260→				model: p.model || "",
261→				provider: p.provider || "",
262→				inputTokens: p.inputTokens || 0,
263→				outputTokens: p.outputTokens || 0,
264→				cacheReadTokens: p.cacheReadTokens || 0,
265→				cacheWriteTokens: p.cacheWriteTokens || 0,
266→				durationMs: p.durationMs || 0,
267→				requestInputTokens: p.requestInputTokens,
268→				requestOutputTokens: p.requestOutputTokens,
269→				requestCacheReadTokens: p.requestCacheReadTokens,
270→				requestCacheWriteTokens: p.requestCacheWriteTokens,
271→				reasoning: p.reasoning || undefined,
272→				audio: p.audio || undefined,
273→				run_id: p.runId || undefined,
274→				created_at: Date.now(),
275→			},
276→			p.messageIndex,
277→		);
278→	}
279→	// Compare against the per-session history index so cross-session
280→	// events aren't wrongly skipped by another session's index.
281→	const evtSession = sessionStore.getByKey(eventSession);
282→	const lastIdx = evtSession ? evtSession.lastHistoryIndex.value : S.lastHistoryIndex;
283→	if (p.messageIndex !== undefined && p.messageIndex <= lastIdx) {
284→		setSessionReplying(eventSession, false);
285→		setSessionActiveRunId(eventSession, null);
286→		return;
287→	}
288→	updateSessionHistoryIndex(eventSession, p.messageIndex);
289→	setSessionReplying(eventSession, false);
290→	setSessionActiveRunId(eventSession, null);
291→	if (!isActive) {
292→		setSessionUnread(eventSession, true);
293→	}
294→	if (!(isActive && isChatPage)) {
295→		S.setVoicePending(false);
296→		return;
297→	}
298→	removeThinking();
299→	clearStaleRunningToolCards();
