 82→export function setSafeMarkdownHtml(el: HTMLElement, text: string): void {
 83→	// Security: renderMarkdown HTML-escapes all input via esc() before
 84→	// applying markdown formatting. No raw user content reaches innerHTML.
 85→	const rendered = renderMarkdown(text);
 86→	el.textContent = "";
 87→	const wrapper = document.createElement("span");
 88→	wrapper.insertAdjacentHTML("afterbegin", rendered);
 89→	while (wrapper.firstChild) el.appendChild(wrapper.firstChild);
