201→function parseMarkdownTable(lines: string[], start: number): TableParseResult | null {
202→	if (start + 1 >= lines.length) return null;
203→	if (!isMarkdownPipeRow(lines[start])) return null;
204→	const headerCells = splitPipeCells(lines[start]);
205→	if (headerCells.length < 2) return null;
206→	if (!isMarkdownSeparatorRow(lines[start + 1], headerCells.length)) return null;
207→
208→	const bodyRows: string[][] = [];
209→	let next = start + 2;
210→	while (next < lines.length) {
211→		const candidate = lines[next];
212→		if (!candidate.trim()) break;
213→		if (!isMarkdownPipeRow(candidate)) break;
214→		bodyRows.push(splitPipeCells(candidate));
215→		next++;
216→	}
217→	return {
218→		html: buildTableHtml(headerCells, bodyRows),
219→		next: next,
220→	};
221→}
222→
223→function isAsciiBorderRow(line: string): boolean {
224→	return /^\+(?:[-=]+\+)+$/.test(stripAnsi(line).trim());
225→}
226→
227→function isAsciiPipeRow(line: string): boolean {
228→	return /^\|.*\|$/.test(stripAnsi(line).trim());
229→}
230→
231→function parseAsciiTable(lines: string[], start: number): TableParseResult | null {
232→	if (!isAsciiBorderRow(lines[start])) return null;
233→	let next = start + 1;
234→	const rows: string[][] = [];
235→
236→	while (next < lines.length) {
237→		const line = lines[next];
238→		if (isAsciiBorderRow(line)) {
239→			next++;
240→			continue;
241→		}
242→		if (!isAsciiPipeRow(line)) break;
243→		rows.push(splitPipeCells(line));
244→		next++;
245→	}
246→	if (rows.length === 0) return null;
247→
248→	return {
249→		html: buildTableHtml(rows[0], rows.slice(1)),
250→		next: next,
251→	};
