147→function stripAnsi(text: string | null | undefined): string {
148→	const input = String(text || "");
149→	let out = "";
150→	for (let i = 0; i < input.length; i++) {
151→		if (input.charCodeAt(i) === 27 && input[i + 1] === "[") {
152→			i += 2;
153→			while (i < input.length) {
154→				const ch = input[i];
155→				if (ch >= "@" && ch <= "~") break;
156→				i++;
157→			}
158→			continue;
159→		}
160→		out += input[i];
161→	}
162→	return out;
