178→function buildTableHtml(headerCells: string[], bodyRows: string[][]): string {
179→	const columnCount = headerCells.length;
180→	const headerRow = normalizeTableRow(headerCells, columnCount);
181→	const bodyHtml = bodyRows
182→		.map((row) => normalizeTableRow(row, columnCount))
183→		.map((row) => `<tr>${row.map((cell) => `<td>${cell}</td>`).join("")}</tr>`)
184→		.join("");
185→	const thead = `<thead><tr>${headerRow.map((cell) => `<th>${cell}</th>`).join("")}</tr></thead>`;
186→	const tbody = bodyRows.length > 0 ? `<tbody>${bodyHtml}</tbody>` : "";
187→	return `<div class="msg-table-wrap"><table class="msg-table">${thead}${tbody}</table></div>`;
