.document-download-btn:hover {
  background: var(--accent);
}
.msg code {
  background: var(--surface2);
  padding: 1px 6px;
  border-radius: 4px;
  font-family: var(--font-mono);
  font-size: 0.85em;
}
.msg pre {
  background: var(--surface);
  padding: 10px 12px;
  border-radius: var(--radius-sm);
  overflow-x: auto;
  margin: 6px 0;
  border: 1px solid var(--border);
}
.msg pre code {
  background: none;
  padding: 0;
}
.msg strong {
  font-weight: 600;
  color: var(--text-strong);
}
.msg-channel-footer {
  font-size: 0.7rem;
  color: var(--muted);
  margin-top: 4px;
}
.theme-toggle {
  display: flex;
  align-items: center;
  gap: 2px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 2px;
}

