/* ══ Chat: Messages, Thinking, Exec Cards, Approval Cards, Token Bar ══ */

.status-dot {
  background: var(--muted);
  border-radius: 50%;
  flex-shrink: 0;
  width: 8px;
  height: 8px;
  transition: background 0.3s;
}

.status-dot.connected {
  background: var(--ok);
  animation: 1.8s ease-out infinite status-live-pulse;
}

.status-dot.connecting {
  background: var(--warn);
  animation: 1s infinite pulse;
}

.status-text-live {
  color: var(--ok) !important;
  font-weight: 600;
  text-shadow: 0 0 8px rgba(34, 197, 94, 0.45);
}

@keyframes status-live-pulse {
  0% {
    box-shadow: 0 0 0 0 rgba(34, 197, 94, 0.55);
  }
  70% {
    box-shadow: 0 0 0 8px rgba(34, 197, 94, 0);
  }
  100% {
    box-shadow: 0 0 0 0 rgba(34, 197, 94, 0);
  }
}

.msg {
  border-radius: var(--radius);
  word-wrap: break-word;
  white-space: pre-wrap;
  max-width: 80%;
  padding: 10px 14px;
  font-size: 0.9rem;
  line-height: 1.6;
  animation: 0.2s ease-out msg-in;
}

.msg.user {
  background: var(--user-bg);
  border: 1px solid var(--user-border);
  color: var(--text);
  align-self: flex-end;
}

.msg.assistant {
  background: var(--assistant-bg);
  border: 1px solid var(--assistant-border);
  color: var(--text);
  align-self: flex-start;
}


.msg.system {
  color: var(--muted);
  background: 0 0;
  align-self: center;
  padding: 4px 0;
  font-size: 0.8rem;
}

.msg.system.system-notice {
  background: var(--surface2);
  background: color-mix(in srgb, var(--surface2) 85%, transparent);
  border: 1px solid var(--border);
  border-color: color-mix(in srgb, var(--border-strong) 65%, transparent);
  border-radius: 999px;
  align-items: center;
  gap: 6px;
  max-width: min(88%, 640px);
  padding: 5px 10px;
  white-space: normal;
  display: inline-flex;
}

.msg.system.system-notice strong {
  color: var(--text);
  font-weight: 600;
}

.msg.system.system-notice.system-notice-sandbox::before {
  content: "";
  background: var(--muted);
  border-radius: 999px;
  flex-shrink: 0;
  width: 6px;
  height: 6px;
}

.msg.system.system-notice.system-notice-sandbox.is-enabled {
  background: var(--surface2);
  background: color-mix(in srgb, var(--ok) 8%, var(--surface2));
  border-color: color-mix(in srgb, var(--ok) 28%, var(--border));
}

.msg.system.system-notice.system-notice-sandbox.is-enabled::before {
  background: var(--ok);
}

.msg.system.system-notice.system-notice-sandbox.is-disabled {
  background: var(--surface2);
  background: color-mix(in srgb, var(--warn) 8%, var(--surface2));
  border-color: color-mix(in srgb, var(--warn) 24%, var(--border));
}

.msg.system.system-notice.system-notice-sandbox.is-disabled::before {
  background: var(--warn);
}

.msg.error {
  color: var(--error);
  background: 0 0;
  align-self: center;
  padding: 4px 0;
  font-size: 0.8rem;
}

.msg.error-card {
  background: var(--surface);
  border: 1px solid var(--error);
  border-radius: 8px;
  align-self: center;
  align-items: flex-start;
  gap: 10px;
  max-width: 420px;
  padding: 12px 16px;
  display: flex;
}

.error-icon {
  flex-shrink: 0;
  font-size: 1.4rem;
  line-height: 1;
}

.error-body {
  flex: 1;
  min-width: 0;
}

.error-title {
  color: var(--error);
  margin-bottom: 2px;
  font-size: 0.85rem;
  font-weight: 600;
}

.error-detail {
  color: var(--fg);
  opacity: 0.85;
  font-size: 0.8rem;
}

.error-continue-btn {
  margin-top: 8px;
  font-size: 0.8rem;
  padding: 4px 16px;
}

.error-countdown {
  color: var(--muted);
  white-space: nowrap;
  flex-shrink: 0;
  align-self: center;
  font-size: 0.75rem;
}

.error-countdown.reset-ready {
