    animation: msg-in 0.2s ease-out;
  }
  .msg.user {
    align-self: flex-end;
    background: var(--user-bg);
    border: 1px solid var(--user-border);
    color: var(--text);
  }
  .queued-tray {
    display: flex;
    flex-direction: column;
    gap: 6px;
    padding: 8px 16px;
    border-top: 1px dashed var(--border);
    background: var(--surface);
  }
  .msg.user.queued {
    opacity: 0.6;
    border-style: dashed;
    max-width: 100%;
    align-self: flex-end;
  }
  .queued-badge {
    display: flex;
    align-items: center;
    gap: 6px;
    margin-top: 6px;
    font-size: 0.75rem;
    color: var(--muted);
  }
  .queued-label {
    font-style: italic;
