	detail_key?: string;
	title_params?: Record<string, unknown>;
	detail_params?: Record<string, unknown>;
}

interface RpcErrorObj {
	code?: string;
	message?: string;
	serverMessage?: string;
}

interface LocalizedRpcError extends RpcErrorObj {
	serverMessage?: string;
}

interface ApiPayload {
	error?: string | RpcErrorObj;
	code?: string;
	message?: string;
}

interface ToolCallArgs {
	command?: string;
	node?: string;
	url?: string;
	query?: string;
	action?: string;
	[key: string]: unknown;
}

interface MapLinks {
	url?: string;
	google_maps?: string;
	apple_maps?: string;
	openstreetmap?: string;
	[key: string]: unknown;
}

interface MapPoint {
	label?: string;
	latitude?: number;
	longitude?: number;
	map_links?: MapLinks;
