			out.push(`</${inList}>`);
			inList = null;
		}

		out.push(line);
	}
	if (inList) out.push(`</${inList}>`);
	if (inBlockquote) out.push("</blockquote>");
	s = out.join("\n");

	// Re-insert code blocks
	s = s.replace(/@@MOLTIS_CODE_BLOCK_(\d+)@@/g, (_: string, idx: string) => {
