				inBlockquote = false;
			}
			const level = headingMatch[1].length;
			out.push(`<h${level}>${headingMatch[2]}</h${level}>`);
			continue;
		}

		// Blockquote (> is HTML-escaped to &gt;)
		const bqMatch = line.match(/^&gt;\s?(.*)$/);
		if (bqMatch) {
			if (inList) {
				out.push(`</${inList}>`);
				inList = null;
			}
			if (!inBlockquote) {
				out.push("<blockquote>");
				inBlockquote = true;
			}
			out.push(bqMatch[1]);
			continue;
		}
		if (inBlockquote) {
			out.push("</blockquote>");
			inBlockquote = false;
		}

		// Unordered list item (- or *)
		const ulMatch = line.match(/^[\s]*[-*]\s+(.+)$/);
		if (ulMatch) {
			if (inList === "ol") {
				out.push("</ol>");
				inList = null;
			}
			if (inList !== "ul") {
				out.push("<ul>");
				inList = "ul";
			}
			out.push(`<li>${ulMatch[1]}</li>`);
			continue;
		}

		// Ordered list item
		const olMatch = line.match(/^[\s]*\d+\.\s+(.+)$/);
		if (olMatch) {
			if (inList === "ul") {
				out.push("</ul>");
				inList = null;
			}
			if (inList !== "ol") {
				out.push("<ol>");
				inList = "ol";
			}
			out.push(`<li>${olMatch[1]}</li>`);
			continue;
		}

		// Close open list if current line is not a list item
		if (inList) {
			out.push(`</${inList}>`);
			inList = null;
		}

		out.push(line);
	}
	if (inList) out.push(`</${inList}>`);
	if (inBlockquote) out.push("</blockquote>");
